mapper.select:
SELECT USERID as userId ,USERNAME as userName ,REGDATE as regDate ,JUMINNO as juminNo ,SYSIP as sysIp ,SYSNAME as sysName ,GUBUNCODE as gubunCode ,TXCODE as txCode ,PAGELANG as pageLang ,REGSITE as regSite ,ENCSIGN as encSign ,DELFLAG as delFlag ,REGDAY as regDay FROM SIGNTRANSACTION WHERE REGDAY IS NOT NULL
AND USERID = #{userId}
AND USERNAME = #{userName}
AND SYSNAME = #{sysName}
AND GUBUNCODE = #{gubunCode}
AND TXCODE = #{txCode}
AND REGSITE LIKE '%' || #{regSite} || '%'
AND REGDAY = #{regDay}
LIMIT 1
